Code Good:
// Input DTO:
#[ApiResource(
    input: CreatePostInput::class,
    output: PostOutput::class,
    processor: PostProcessor::class,
    provider: PostProvider::class
)]
class Post { ... }

class CreatePostInput {
    #[Assert\NotBlank]
    public string $title;
    #[Assert\NotBlank]
    public string $body;
}

class PostProcessor implements ProcessorInterface {
    public function process(mixed $data, Operation $operation, array $context = []): Post {
        $post = new Post();
        $post->setTitle($data->title);
        $post->setBody($data->body);
        $this->em->persist($post);
        $this->em->flush();
        return $post;
    }
}

