Code Good:
class Post {
    #[Groups(['post:read', 'post:list'])]
    private ?int $id;

    #[Groups(['post:read', 'post:list', 'post:write'])]
    private string $title;

    #[Groups(['post:read', 'post:write'])]
    private string $body;  // Only in detail, not list

    #[Groups(['post:read'])]
    private User $author;   // Read-only
}

#[ApiResource(
    normalizationContext: ['groups' => ['post:read']],
    denormalizationContext: ['groups' => ['post:write']],
    operations: [
        new GetCollection(normalizationContext: ['groups' => ['post:list']]),
    ]
)]

