Code Good:
class PostApiTest extends ApiTestCase {
    public function testGetCollection(): void {
        PostFactory::createMany(30);
        $response = static::createClient()->request('GET', '/api/posts');
        $this->assertResponseIsSuccessful();
        $this->assertJsonContains(['hydra:totalItems' => 30]);
        $this->assertCount(20, $response->toArray()['hydra:member']);
    }
    public function testCreatePost(): void {
        $response = static::createClient()->request('POST', '/api/posts', [
            'json' => ['title' => 'New Post', 'body' => 'Content here']
        ]);
        $this->assertResponseStatusCodeSame(201);
        $this->assertJsonContains(['title' => 'New Post']);
    }
}
